class Solution:
    def separateSquares(self, squares):
        ys = sorted(set([y for _, y, l in squares] + [y + l for _, y, l in squares]))
        total = 0.0
        slab_data = []
        for i in range(len(ys) - 1):
            Ya, Yb = ys[i], ys[i + 1]
            mid = (Ya + Yb) / 2
            intervals = []
            for x, y, l in squares:
                if y <= Ya and y + l >= Yb:
                    intervals.append((x, x + l))
            union_len = 0.0
            if intervals:
                intervals.sort()
                cur_s, cur_e = intervals[0]
                for s, e in intervals[1:]:
                    if s > cur_e:
                        union_len += cur_e - cur_s
                        cur_s, cur_e = s, e
                    else:
                        cur_e = max(cur_e, e)
                union_len += cur_e - cur_s
            h = Yb - Ya
            slab_data.append((Ya, Yb, union_len))
            total += union_len * h

        target = total / 2
        cum = 0.0
        for Ya, Yb, union_len in slab_data:
            full = union_len * (Yb - Ya)
            if union_len == 0:
                continue
            if cum + full >= target:
                remaining = target - cum
                return Ya + remaining / union_len
            cum += full
        return ys[-1]

