var separateSquares = function(squares) {
    const ySet = new Set();
    for (const [, y, l] of squares) {
        ySet.add(y);
        ySet.add(y + l);
    }
    const ys = [...ySet].sort((a, b) => a - b);
    let total = 0;
    const slabData = [];
    for (let i = 0; i < ys.length - 1; i++) {
        const Ya = ys[i], Yb = ys[i + 1];
        const intervals = [];
        for (const [x, y, l] of squares) {
            if (y <= Ya && y + l >= Yb) intervals.push([x, x + l]);
        }
        intervals.sort((a, b) => a[0] - b[0]);
        let unionLen = 0;
        if (intervals.length > 0) {
            let curS = intervals[0][0], curE = intervals[0][1];
            for (let j = 1; j < intervals.length; j++) {
                const [s, e] = intervals[j];
                if (s > curE) {
                    unionLen += curE - curS;
                    curS = s; curE = e;
                } else {
                    curE = Math.max(curE, e);
                }
            }
            unionLen += curE - curS;
        }
        const h = Yb - Ya;
        slabData.push([Ya, Yb, unionLen]);
        total += unionLen * h;
    }
    const target = total / 2;
    let cum = 0;
    for (const [Ya, Yb, unionLen] of slabData) {
        const full = unionLen * (Yb - Ya);
        if (unionLen === 0) continue;
        if (cum + full >= target) {
            const remaining = target - cum;
            return Ya + remaining / unionLen;
        }
        cum += full;
    }
    return ys[ys.length - 1];
};
